$(document).ready(function() {
    var baseUrl = window.location.origin;
    let retrive_data = baseUrl+'/get_all_customer_ajax';
    let edit_category = baseUrl+'/master/customer/edit_customer';
    // Initialize DataTable
    $('#view_customer').DataTable({
        processing: true,
        serverSide: true,
        searching: true,
        scrollY: 500,
        scrollX: true,
        scrollCollapse: true,
        
        columnDefs: [{
            "defaultContent": "-",
            "targets": 0,
            "render": function (data, type, row, meta) {
              // Return the serial number (row index + 1)
              return meta.row + 1;
            }
          }],
        ajax: {
            url: retrive_data,
        },

        "columns": [
          { "data": null }, // This column will be used for serial numbers
             
            { 
              "data": "customer_name",

            },
            {
                "data": "mobile_no",
            },
            {
                "data": "valaya_name",
            },
            {
                "data": "address",
            },
          { 
            title: 'Edit',
            render: function(data, type, full) {
                return `
                <a href='edit_customer/${full.id}'><i class="ti-pencil-alt"></i></a>
                 `;      
            }
        }

        ]
    });
});